import socket
import json
import threading
import time
from typing import Dict, List, Any

class GameServer:
    def __init__(self, host: str = '0.0.0.0', port: int = 27015):
        self.host = host
        self.port = port
        self.socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.socket.bind((self.host, self.port))
        self.players: List[Dict[str, Any]] = []
        self.game_state = {
            'map': 'unknown',
            'players': 0,
            'max_players': 20,
            'game_mode': 'unknown',
            'server_name': 'Game Server',
            'version': '1.0.0'
        }
        self.running = False
        
    def add_player(self, player_data: Dict[str, Any]):
        self.players.append(player_data)
        self.game_state['players'] = len(self.players)
        
    def remove_player(self, player_id: str):
        self.players = [p for p in self.players if p.get('id') != player_id]
        self.game_state['players'] = len(self.players)
        
    def update_game_state(self, state_update: Dict[str, Any]):
        self.game_state.update(state_update)
        
    def handle_query(self, data: bytes, client_address: tuple) -> bytes:
        try:
            query = data.decode('utf-8').strip()
            if query == 'status':
                response = self.get_status_response()
                return json.dumps(response).encode('utf-8')
            elif query == 'ping':
                return b'pong'
            else:
                return b'unknown query'
        except Exception:
            return b'error'
            
    def get_status_response(self) -> Dict[str, Any]:
        return {
            'server': self.game_state,
            'players': self.players,
            'timestamp': time.time(),
            'response_size': len(json.dumps({
                'server': self.game_state,
                'players': self.players
            }).encode('utf-8'))
        }
        
    def start(self):
        self.running = True
        print(f"Game server started on {self.host}:{self.port}")
        
        while self.running:
            try:
                data, client_address = self.socket.recvfrom(4096)
                response = self.handle_query(data, client_address)
                
                # Send response with error handling
                try:
                    self.socket.sendto(response, client_address)
                except Exception as e:
                    print(f"Error sending response to {client_address}: {e}")
                    
            except Exception as e:
                if self.running:
                    print(f"Error handling query: {e}")
                    
    def stop(self):
        self.running = False
        self.socket.close()

# Secure server instance
server = GameServer()

